<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clear-cooldown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic:me@example.com</span></span>
